#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
    int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
    while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int qpow(int a,int b,int Mod)
{
    int res=1;while(b)
    {
        if(b&1)res=1ll*res*a%Mod;
        a=1ll*a*a%Mod;b>>=1;
    }
    return res;
}
inline bool isp(int x)
{
    for(int i=2;i*i<=x;++i)if(x%i==0)return false;
    return true;
}
bool f1;
const int N=5050;
const int M1=982387097,M2=974230813,B1=479,B2=743;
int p1[N],p2[N],i1[N],i2[N];
struct Hash
{
    int h1,h2;inline Hash(int H1=0,int H2=0){h1=H1;h2=H2;}
    inline Hash operator + (Hash Q)
    {
        return Hash((h1+Q.h1)%M1,(h2+Q.h2)%M2);
    }
    inline Hash operator - (Hash Q)
    {
        return Hash((h1-Q.h1+M1)%M1,(h2-Q.h2+M2)%M2);
    }
    inline Hash operator << (int x)
    {
        return Hash(1ll*h1*p1[x]%M1,1ll*h2*p2[x]%M2);
    }
    inline Hash operator >> (int x)
    {
        return Hash(1ll*h1*i1[x]%M1,1ll*h2*i2[x]%M2);
    }
    inline bool operator == (const Hash&Q)const{return Q.h1==h1&&Q.h2==h2;}
    inline bool operator != (const Hash&Q)const{return Q.h1!=h1||Q.h2!=h2;}
};
 const int M=262144,B=998244353;
//const int M=42643729,B=998244353;
// const int M=56352563,B=998244353;
struct HashMap
{
    Hash idx[M];int t[M],stk[M],top;inline HashMap(){top=0;}
    inline void add(Hash x)
    {
        int hsh=(1ll*x.h1*B+x.h2)&262143;
        while(t[hsh]!=0&&idx[hsh]!=x)hsh=(hsh+1==M?0:(hsh+1));
        if(t[hsh]==0)idx[hsh]=x,stk[++top]=hsh;++t[hsh];
    }

    inline int cnt(Hash x)
    {
        int hsh=(1ll*x.h1*B+x.h2)%M;
        while(t[hsh]!=0&&idx[hsh]!=x)hsh=(hsh+1==M?0:(hsh+1));
        return t[hsh];
    }
    inline void clear()
    {
        while(top)
        {
            int u=stk[top--];
            idx[u]=Hash();t[u]=0;
        }
    }
}S;
int pre[N][N],n,g[N][N];Hash sum[N];char s[N];long long ans;
inline Hash Get(int l,int r){return (sum[r]-sum[l-1])>>l;}
inline int Sum(int *s,int l,int r){if(l>r)return 0;return s[r]-s[l-1];}
bool f2;

inline void Solve()
{
    scanf("%s",s+1);n=strlen(s+1);
    S.clear();
    rep(1,n,i)
    {
        sum[i]=sum[i-1]+(Hash(s[i],s[i])<<i);
        // printf("%d :: %d %d\n",i,sum[i].h1,sum[i].h2);
    }
    rep(2,n,l)
    {
        rep(0,n,r)pre[l][r]=0;
        rep(l,n,r)
        {
            if(l-(r-l+1)<1)break;
            pre[l][r]=(Get(l-(r-l+1),l-1)==Get(l,r));
        }
        rep(l+1,n,r)pre[l][r]+=pre[l][r-1];
    }
    rep(1,n,Len)
    {
        S.clear();
        drep(n-Len-1,Len,r)//114(r)514
        {
            S.add(Get(r+2,r+1+Len));
            g[r-Len+1][r]=S.cnt(Get(r-Len+1,r));
        }
    }
    ans=0;
    drep(n-2,1,r)//114(r)514
    {
        //Add [r+2,i] strings
        // rep(r+2,n,i)S.add(Get(r+2,i));
        drep(r-1,1,l)
        {
            //if 14 out
            if(r+1+(r-l+1)>n)break;
            // int glr=S.cnt(Get(l,r));
            int flr=Sum(pre[l],l,r-1);
            int glr=g[l][r];
            ans+=1ll*glr*flr;
            // printf("[%d,%d] :: %d %d\n",l,r,flr,glr);
        }
    }
    printf("%lld\n",ans);
}
int main()
{
    // rep(int(4e7),int(4.5e7),i)if(isp(i))printf("%d\n",i);
    // printf("Mem :: %.6lf\n",1.*(&f1-&f2)/1024/1024);
    // return 0;
    p1[0]=p2[0]=i1[0]=i2[0]=1;
    rep(1,N-5,i)
    {
        p1[i]=1ll*B1*p1[i-1]%M1;
        p2[i]=1ll*B2*p2[i-1]%M2;
        i1[i]=qpow(p1[i],M1-2,M1);
        i2[i]=qpow(p2[i],M2-2,M2);
    }
    int T=read();
    while(T--)Solve();
    return 0;
}
